mapper.insert:
/* ====== cmn.fileup2.insertCmnFileUpldMgmtMst =========*/

    INSERT INTO MSP_MNG.CMN_FILE_UPLD_MGMT_MST 
    (
	   	 USR_ID
	   , MENU_ID
	   , FILE_UPLD_DT
	   , FILE_NM
	   , FILE_DESC
	   , DUTY_NM
	   , FILE_URL
	   , FILE_SIZE
	   , DATA_CNT
	 ) 
	VALUES
	 ( 
	   	 #{SESSION_USER_ID}
	   , nvl(#{menuId},'*')
	   , sysdate
	   , #{FILE_NM}
	   , #{FILE_DESC}
	   , #{DUTY_NM}
	   , #{FILE_URL}
	   , #{FILE_SIZE}
	   , #{DATA_CNT}
	 )

/* ====== cmn.fileup2.insertFileMgmtMst =========*/

    INSERT INTO CMN_FILE_MGMT_MST 
	(
		 FILE_ID
		, MODULE_ID
		, FILE_NM
		, FILE_NM_PC
		, FILE_ROUT
		, FILE_SIZE
		, REGST_ID
		, REG_DTTM
		, RVISN_ID
		, RVISN_DTTM
	) 
	VALUES 
	( 
		  #{fileId }
		, #{moduleId }
		, #{fileNm }
		, #{fileNmPc}
		, #{fileRout}
		, #{fileSize}
		, #{SESSION_USER_ID }
		, SYSDATE
		, #{SESSION_USER_ID }
		, SYSDATE
	)

mapper.delete:
/* ====== cmn.fileup2.deleteFileMgmtById =========*/

	DELETE CMN_FILE_MGMT_MST
	WHERE FILE_ID    =  #{fileId} 
	  AND MODULE_ID  =  #{moduleId}
